    "url": "./movie-1523.html",
    "cover": "./23.jpg",
    "year": 2025,
    "region": "中国大陆",
    "type": "电影",
    "category": "年度新剧",
    "categoryUrl": "./category-11.html",
    "genre": "悬疑, 古装, 犯罪",
